    workflows: [
      {
        name: 'Trucking Record Lifecycle',
        entity: 'TruckingRecord',
        states: ["draft","submitted","assigned","in-progress","review","revision-needed","approved","completed","archived"],
        transitions: [
          { from: 'draft', to: 'submitted', action: 'Submit for Processing', role: 'staff' },
          { from: 'submitted', to: 'assigned', action: 'Assign to Staff', role: 'manager' },
          { from: 'assigned', to: 'in-progress', action: 'Start Processing', role: 'staff' },
          { from: 'in-progress', to: 'review', action: 'Submit for Review', role: 'staff' },
          { from: 'review', to: 'revision-needed', action: 'Request Revisions', role: 'manager' },
          { from: 'revision-needed', to: 'in-progress', action: 'Address Revisions', role: 'staff' },
          { from: 'review', to: 'approved', action: 'Approve', role: 'manager' },
          { from: 'approved', to: 'completed', action: 'Mark Complete', role: 'staff' },
          { from: 'completed', to: 'archived', action: 'Archive Record', role: 'system' },
        ],
      },
      {
        name: 'Client Engagement',
        entity: 'Client',
        states: ["prospect","qualification","proposal","negotiation","onboarding","active-service","review","renewal","inactive"],
        transitions: [
          { from: 'prospect', to: 'qualification', action: 'Qualify Lead', role: 'sales' },
          { from: 'qualification', to: 'proposal', action: 'Send Proposal', role: 'sales' },
          { from: 'proposal', to: 'negotiation', action: 'Begin Negotiation', role: 'sales' },
          { from: 'negotiation', to: 'onboarding', action: 'Win Client', role: 'sales' },
          { from: 'onboarding', to: 'active-service', action: 'Complete Onboarding', role: 'account-manager' },
          { from: 'active-service', to: 'review', action: 'Initiate Review', role: 'account-manager' },
          { from: 'review', to: 'renewal', action: 'Renew Contract', role: 'account-manager' },
          { from: 'renewal', to: 'active-service', action: 'Contract Renewed', role: 'system' },
          { from: 'active-service', to: 'inactive', action: 'Deactivate Client', role: 'manager' },
        ],
      },
      {
        name: 'Invoice Processing',
        entity: 'Invoice',
        states: ["draft","internal-review","approved","sent","payment-received","partially-paid","overdue","collections","closed"],
        transitions: [
          { from: 'draft', to: 'internal-review', action: 'Submit for Review', role: 'billing-clerk' },
          { from: 'internal-review', to: 'approved', action: 'Approve Invoice', role: 'manager' },
          { from: 'internal-review', to: 'draft', action: 'Return for Edits', role: 'manager' },
          { from: 'approved', to: 'sent', action: 'Send to Client', role: 'billing-clerk' },
          { from: 'sent', to: 'payment-received', action: 'Record Full Payment', role: 'billing-clerk' },
          { from: 'sent', to: 'partially-paid', action: 'Record Partial Payment', role: 'billing-clerk' },
          { from: 'sent', to: 'overdue', action: 'Mark Overdue', role: 'system' },
          { from: 'overdue', to: 'collections', action: 'Send to Collections', role: 'manager' },
          { from: 'partially-paid', to: 'payment-received', action: 'Receive Remaining', role: 'billing-clerk' },
          { from: 'payment-received', to: 'closed', action: 'Close Invoice', role: 'system' },
        ],
      },
      {
        name: 'Employee Onboarding',
        entity: 'Employee',
        states: ["offer-sent","offer-accepted","background-check","documentation","orientation","training","active"],
        transitions: [
          { from: 'offer-sent', to: 'offer-accepted', action: 'Accept Offer', role: 'candidate' },
          { from: 'offer-accepted', to: 'background-check', action: 'Start Background Check', role: 'hr' },
          { from: 'background-check', to: 'documentation', action: 'Complete Documentation', role: 'hr' },
          { from: 'documentation', to: 'orientation', action: 'Schedule Orientation', role: 'hr' },
          { from: 'orientation', to: 'training', action: 'Begin Training', role: 'manager' },
          { from: 'training', to: 'active', action: 'Complete Training', role: 'manager' },
        ],
      },
    ],
